import{_ as i,o as l,c as n,ag as t}from"./chunks/framework.DXGyWiRo.js";const r="/images/lekt4005.jpg",a="/images/lekt4003.jpg",s="/images/lekt4002.jpg",o="/images/lekt4001.jpg",p="/images/lekt4004.jpg",g=JSON.parse('{"title":"Lektion 40","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion40.md","filePath":"lektionen/lektion40.md"}'),u={name:"lektionen/lektion40.md"};function h(d,e,m,c,f,k){return l(),n("div",null,[...e[0]||(e[0]=[t('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-40" tabindex="-1">Lektion 40 <a class="header-anchor" href="#lektion-40" aria-label="Permalink to &quot;Lektion 40&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>40.1. सुभाषितानि</li><li>40.2. Bildung der Verbformen der ersten Person Perfekt (लिट्) <ul><li>40.2.1. Perfekt Typ I: keine Stammabstufung</li><li>40.2.2. Perfekt Typ II: starker Stamm Hochstufe, schwacher Stamm Tiefstufe</li><li>40.2.3. Perfekt Typ III: Starker Stamm Hochstufe/Dehnstufe <ul><li>40.2.3.1. Perfekt Typ IIIa: Starker Stamm Hochstufe/Dehnstufe, schwacher Stamm Tiefstufe</li><li>40.2.3.2. Perfekt Typ IIIb: Starker Stamm Hochstufe/Dehnstufe, schwacher Stamm Hochstufe</li></ul></li><li>40.2.4. Perfekt Typ IV: Wurzeln auf -ā / -ai</li><li>40.2.5. Perfekt Typ V: Konsonant-a-Konsonant <ul><li>40.2.5.1. Perfekt Typ Va: Konsonant-a-Konsonant, schwacher Stamm Tiefstufe</li><li>40.2.5.2. Perfekt Typ Vb: Konsonant-a-Konsonant, Anfangskonsonant kein Guttural, Aspirat, h, Schwacher Stamm ohne Reduplikation, mit -e-</li><li>40.2.5.3. Perfekt Typ Vc: Konsonant-a-Konsonant, schwacher Stamm Hochstufe</li></ul></li><li>40.2.6. Besondere Perfekt-Bildungen</li></ul></li><li>40.3. Bildung der Verbformen der ersten Person des periphrastischen Perfekt (अनुप्रयोगलिट्)</li><li>40.4. Syntaktisches zur ersten Person (तृतीयः)</li><li>40.5. Personalpronomen (पुरुषार्थकसर्वनाम) der 1. Person Singular und Plural</li><li>40.6. Wortliste</li><li>40.7. Übung</li><li>40.8. Wiederholungsübung zur Formenlehre</li></ul><h2 id="_40-1-सुभाषितानि" tabindex="-1">40.1. सुभाषितानि <a class="header-anchor" href="#_40-1-सुभाषितानि" aria-label="Permalink to &quot;40.1. सुभाषितानि&quot;">​</a></h2><blockquote><p>विद्या ददाति विनयं<br> विनयाद्याति पात्रताम् ।<br> पात्रत्वाद्धनमाप्नोति<br> धनाद्धर्मं ततः सुखम् ॥१॥</p><p>सुखार्थी चेत्त्यजेद्विद्यां<br> विद्यार्थी चेत्त्यजेत्सुखम् ।<br> सुखार्थिनः कुतो विद्या<br> कुतो विद्यार्थिनः सुखम् ॥२॥</p><p>आचार्यात्पादमादत्ते<br> पादं शिष्यः स्वमेधया ।<br> पादं सब्रह्मचारिभ्यः<br> पादं कालक्रमेण च ॥३॥</p></blockquote><p><img src="'+r+'" alt=""><br> Abb.: पादं सब्रह्मचारिभ्<br> Vadaseri, Thanjavur District = தஞ்சாவூர் மாவட்டம்<br> [Bildquelle: kifo. -- <a href="http://www.flickr.com/photos/turningpoint/2209292/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/turningpoint/2209292/</a>. -- Zugriff am 2009-01-02. -- <a href="http://creativecommons.org/licenses/by-sa/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, share alike)]</p><h2 id="_40-2-bildung-der-verbformen-der-ersten-person-perfekt-लिट्" tabindex="-1">40.2. Bildung der Verbformen der ersten Person Perfekt (लिट्) <a class="header-anchor" href="#_40-2-bildung-der-verbformen-der-ersten-person-perfekt-लिट्" aria-label="Permalink to &quot;40.2. Bildung der Verbformen der ersten Person Perfekt (लिट्)&quot;">​</a></h2><p>Endungen der ersten Person (तृतीयः) im Perfekt (लिट्)</p><table tabindex="0"><thead><tr><th>परस्मैपदम्</th><th>आत्मनेपदम्</th></tr></thead><tbody><tr><td>एकवचनम्</td><td>बहुवचनम्</td></tr><tr><td>-a</td><td>-ma</td></tr></tbody></table><p>Beachten Sie, dass die Endungen der 1. Personen Singular P,Ā mit denen der 3. Person Singular identisch sind. Deshalb sind in allen Perfekttypen außer Typ III(a,b) und Typ V(a,b,c) die Formen der 1. Singular P bzw. Ā immer identisch mit denen der 3. Singular P bzw. Ā.</p><p>Bei Typ IV endet die 1. sg. P. wie die 3.sg.P. auf -au.</p><p>Bei den Perfekttypen III und V ist die 1. Singular Ā immer identisch mit der 3. Singular Ā.</p><p>Bei den Perfekttypen III und V sind die 1. Singular P und die 3. Singular P wahlweise identisch: die 3.sg.P muss bei diesen Bildungstypen immer dehnstufig sein, die 1.sg.P kann wahlweise hochstufig oder dehnstufig sein.</p><p>Vor konsonantisch anlautende Endungen tritt bei der Mehrzahl der Wurzeln der Bindevokal -i-.</p><p>Außer vor die Endung -re, vor die immer -i- treten muss, das der Bindevokal vor konsonantisch anlautende Endungen niemals treten bei acht Wurzeln auf -ṛ bzw. -u, nämlich</p><ol><li>कृ 8U (außer संस्कृ)</li><li>भृ 1U</li><li>वृ 9U &quot;wählen&quot;</li><li>सृ 1P</li><li>द्रु 1p &quot;rennen&quot;</li><li>श्रु 5P</li><li>स्तु 2U</li><li>स्रु 1P &quot;fließen&quot;</li></ol><p>Bei sog. fakultativen अनिट्-Wurzeln kann der Bindevokal wahlweise eingeschoben werden oder nicht. (Aufzählung dieser Wurzeln bei Kielhorn, Grammatik S. 92 § 298b,2,3)</p><h3 id="_40-2-1-perfekt-typ-i-keine-stammabstufung" tabindex="-1">40.2.1. Perfekt Typ I: keine Stammabstufung <a class="header-anchor" href="#_40-2-1-perfekt-typ-i-keine-stammabstufung" aria-label="Permalink to &quot;40.2.1. Perfekt Typ I: keine Stammabstufung&quot;">​</a></h3><p>1.sg. = 3.sg.</p><p>Verben, die diesem Typ folgen:</p><ul><li>Konsonant-Langvokal-Konsonant</li><li>Konsonant-Vokal-Konsonant-Konsonant</li><li>a-Konsonant(-Konsonant)</li><li>ā-Konsonant</li></ul><p>बन्ध् 9P</p><ul><li>1.sg.P बबन्ध</li><li>1.pl.P बबन्धिम</li></ul><p>जीव् 1P</p><ul><li><p>1.sg.P जिजीव</p></li><li><p>1.pl.P जिजिविम</p></li></ul><p>अश् 5Ā</p><ul><li><p>1.sg.Ā आनशे</p></li><li><p>1.pl.Ā आनशिमहे</p></li></ul><p>अस् 2P und अस् 4P</p><ul><li><p>1.sg.P आस</p></li><li><p>1.pl.P आसिम (a + as-i-ma)</p></li></ul><h3 id="_40-2-2-perfekt-typ-ii-starker-stamm-hochstufe-schwacher-stamm-tiefstufe" tabindex="-1">40.2.2. Perfekt Typ II: starker Stamm Hochstufe, schwacher Stamm Tiefstufe <a class="header-anchor" href="#_40-2-2-perfekt-typ-ii-starker-stamm-hochstufe-schwacher-stamm-tiefstufe" aria-label="Permalink to &quot;40.2.2. Perfekt Typ II: starker Stamm Hochstufe, schwacher Stamm Tiefstufe&quot;">​</a></h3><p>Verben, die diesem Typ folgen:</p><ul><li>(Konsonant-)i/u/ṛ/ḷ-Konsonant</li></ul><p>भिद् 7U</p><ul><li><p>1.sg.P बिभेद</p></li><li><p>1.pl.P बिभिदिम</p></li><li><p>1.sg.Ā बिभिदे</p></li><li><p>1.pl.Ā बुभिदिमहे</p></li></ul><p>मुह् 4P fakultativ अनिट्</p><ul><li><p>1.sg.P मुमोह</p></li><li><p>1.pl.P मुमुहिम । मुमुह्म</p></li></ul><h3 id="_40-2-3-perfekt-typ-iii-starker-stamm-hochstufe-dehnstufe" tabindex="-1">40.2.3. Perfekt Typ III: Starker Stamm Hochstufe/Dehnstufe <a class="header-anchor" href="#_40-2-3-perfekt-typ-iii-starker-stamm-hochstufe-dehnstufe" aria-label="Permalink to &quot;40.2.3. Perfekt Typ III: Starker Stamm Hochstufe/Dehnstufe&quot;">​</a></h3><p>1.sg.P wahlweise hochstufig oder dehnstufig</p><h4 id="_40-2-3-1-perfekt-typ-iiia-starker-stamm-hochstufe-dehnstufe-schwacher-stamm-tiefstufe" tabindex="-1">40.2.3.1. Perfekt Typ IIIa: Starker Stamm Hochstufe/Dehnstufe, schwacher Stamm Tiefstufe <a class="header-anchor" href="#_40-2-3-1-perfekt-typ-iiia-starker-stamm-hochstufe-dehnstufe-schwacher-stamm-tiefstufe" aria-label="Permalink to &quot;40.2.3.1. Perfekt Typ IIIa: Starker Stamm Hochstufe/Dehnstufe, schwacher Stamm Tiefstufe&quot;">​</a></h4><p>Verben, die diesem Typ folgen:</p><ul><li>(Konsonant-)(Konsonant-)i/ī/u/ū</li><li>(Konsonant-)-ṛ</li></ul><p>इ 2P</p><ul><li><p>1.sg.P इयाय । इयय (i+e+a)</p></li><li><p>1.pl.P ईयिम (i+iy+i+ma)</p></li></ul><p>नी 1U</p><ul><li><p>1.sg.P निनाय । निनय</p></li><li><p>1.pl.P निन्यिम (ni-nī + i + ma !!!)</p></li><li><p>1.sg.Ā निन्ये</p></li><li><p>1.pl.Ā निन्यिमहे</p></li></ul><p>स्तु 2U strikt अनिट्</p><ul><li><p>1.sg.P तुष्टाव । तुष्टव (tu-sto + a)</p></li><li><p>1.pl.P तुष्टुम</p></li><li><p>1.sg.Ā तुष्टुवे</p></li><li><p>1.pl.Ā तुष्टुमहे</p></li></ul><p>कृ 8U strikt अनिट्</p><ul><li><p>1.sg.P चकार । चकर</p></li><li><p>1.pl.P चकृम</p></li><li><p>1.sg.Ā चक्रे</p></li><li><p>1.pl.Ā चकृमहे</p></li></ul><h4 id="_40-2-3-2-perfekt-typ-iiib-starker-stamm-hochstufe-dehnstufe-schwacher-stamm-hochstufe" tabindex="-1">40.2.3.2. Perfekt Typ IIIb: Starker Stamm Hochstufe/Dehnstufe, schwacher Stamm Hochstufe <a class="header-anchor" href="#_40-2-3-2-perfekt-typ-iiib-starker-stamm-hochstufe-dehnstufe-schwacher-stamm-hochstufe" aria-label="Permalink to &quot;40.2.3.2. Perfekt Typ IIIb: Starker Stamm Hochstufe/Dehnstufe, schwacher Stamm Hochstufe&quot;">​</a></h4><p>Verben, die diesem Typ folgen:</p><ul><li>(Konsonant-)(Konsonant-)-ṝ</li><li>Konsonant-Konsonant-ṛ</li></ul><p>पॄ 3P</p><ul><li><p>1.sg.P पपार । पपर</p></li><li><p>1.pl.P पपरिम#्</p></li></ul><p>स्मृ 1P</p><ul><li><p>1.sg.P सस्मार । सस्मर</p></li><li><p>1.pl.P सस्मरिम</p></li></ul><p>संस्कृ 8U</p><ul><li><p>1.sg.P सञ्चस्कार । सञ्चस्कर</p></li><li><p>1.pl.P सञ्चस्करिम</p></li><li><p>1.sg.Ā सञ्चस्करे</p></li><li><p>1.pl.Ā सञ्चस्करिमहे</p></li></ul><h3 id="_40-2-4-perfekt-typ-iv-wurzeln-auf-a-ai" tabindex="-1">40.2.4. Perfekt Typ IV: Wurzeln auf -ā / -ai <a class="header-anchor" href="#_40-2-4-perfekt-typ-iv-wurzeln-auf-a-ai" aria-label="Permalink to &quot;40.2.4. Perfekt Typ IV: Wurzeln auf -ā / -ai&quot;">​</a></h3><ul><li>Starker Stamm: <ul><li>1.,3. sg. Parasamaip.: -au</li></ul></li><li>Schwacher Stamm: <ul><li>vor Konsonant: Tiefstufe-i</li><li>vor Vokal: Tiefstufe-ø</li></ul></li></ul><p>दा 3U</p><ul><li><p>1.sg.P ददौ</p></li><li><p>1.pl.P ददिम (da-d-i-ma)</p></li><li><p>1.sg.Ā ददे</p></li><li><p>1.pl.Ā ददिमहे</p></li></ul><h3 id="_40-2-5-perfekt-typ-v-konsonant-a-konsonant" tabindex="-1">40.2.5. Perfekt Typ V: Konsonant-a-Konsonant <a class="header-anchor" href="#_40-2-5-perfekt-typ-v-konsonant-a-konsonant" aria-label="Permalink to &quot;40.2.5. Perfekt Typ V: Konsonant-a-Konsonant&quot;">​</a></h3><p>1.sg.P. wahlweise hochstufig oder dehnstufig</p><h4 id="_40-2-5-1-perfekt-typ-va-konsonant-a-konsonant-schwacher-stamm-tiefstufe" tabindex="-1">40.2.5.1. Perfekt Typ Va: Konsonant-a-Konsonant, schwacher Stamm Tiefstufe <a class="header-anchor" href="#_40-2-5-1-perfekt-typ-va-konsonant-a-konsonant-schwacher-stamm-tiefstufe" aria-label="Permalink to &quot;40.2.5.1. Perfekt Typ Va: Konsonant-a-Konsonant, schwacher Stamm Tiefstufe&quot;">​</a></h4><p>Verben, die diesem Typ folgen:</p><blockquote><ol><li>gam &quot;gehen&quot;</li><li>han (»ghan) &quot;erschlagen&quot;</li><li>jan &quot;geboren werden&quot;</li><li>vac &quot;sprechen&quot;</li><li>vad &quot;sprechen&quot;</li><li>yaj &quot;opfern&quot;</li><li>u.a.</li></ol></blockquote><p>गम् 1P</p><ul><li><p>1.sg.P जगाम । जगम</p></li><li><p>1.pl.P जग्मिम (ja-gm-i-ma)</p></li></ul><p>हन् 2P</p><ul><li><p>1.sg.P जघान । जघन</p></li><li><p>1.pl.P जघ्निम</p></li></ul><p>जन् 4Ā</p><ul><li><p>1.sg.Ā जज्ञे</p></li><li><p>1.pl.Ā जज्ञिमहे</p></li></ul><p>वच् 2P</p><ul><li><p>1.sg.P उवाच । उवच</p></li><li><p>1.pl.P ऊचिम (u + uc-ima)</p></li></ul><p>वद् 1P (Ā)</p><ul><li><p>1.sg.P उवाद । उवद</p></li><li><p>1.pl.P ऊदिम</p></li><li><p>1.sg.Ā ऊदे</p></li><li><p>1.pl.Ā  ऊदिमहे</p></li></ul><p>यज् 1U</p><ul><li><p>1.sg.P इयाज । इयज</p></li><li><p>1.pl.P ईजिम</p></li><li><p>1.sg.Ā ईजे</p></li><li><p>1.pl.Ā ईजिमहे</p></li></ul><h4 id="_40-2-5-2-perfekt-typ-vb-konsonant-a-konsonant-anfangskonsonant-kein-guttural-aspirat-h-schwacher-stamm-ohne-reduplikation-mit-e" tabindex="-1">40.2.5.2. Perfekt Typ Vb: Konsonant-a-Konsonant, Anfangskonsonant kein Guttural, Aspirat, h, Schwacher Stamm ohne Reduplikation, mit -e- <a class="header-anchor" href="#_40-2-5-2-perfekt-typ-vb-konsonant-a-konsonant-anfangskonsonant-kein-guttural-aspirat-h-schwacher-stamm-ohne-reduplikation-mit-e" aria-label="Permalink to &quot;40.2.5.2. Perfekt Typ Vb: Konsonant-a-Konsonant, Anfangskonsonant kein Guttural, Aspirat, h, Schwacher Stamm ohne Reduplikation, mit -e-&quot;">​</a></h4><p>पच् 1U</p><ul><li><p>1.sg.P पपाच । पपच</p></li><li><p>1.pl.P पेचिम</p></li><li><p>1.sg.Ā पेचे</p></li><li><p>1.pl.Ā पेचिमहे</p></li></ul><h4 id="_40-2-5-3-perfekt-typ-vc-konsonant-a-konsonant-schwacher-stamm-hochstufe" tabindex="-1">40.2.5.3. Perfekt Typ Vc: Konsonant-a-Konsonant, schwacher Stamm Hochstufe <a class="header-anchor" href="#_40-2-5-3-perfekt-typ-vc-konsonant-a-konsonant-schwacher-stamm-hochstufe" aria-label="Permalink to &quot;40.2.5.3. Perfekt Typ Vc: Konsonant-a-Konsonant, schwacher Stamm Hochstufe&quot;">​</a></h4><p>Verben, die diesem Typ folgen:</p><ul><li>Alle übrigen Wurzeln mit mittlerem -a-</li></ul><p>क्रम् 1U</p><ul><li><p>1.sg.P चक्राम । चक्रम</p></li><li><p>1.pl.P चक्रमिम</p></li><li><p>1.sg.Ā चक्रमे</p></li><li><p>1.pl.Ā चक्रमिमहे</p></li></ul><h3 id="_40-2-6-besondere-perfekt-bildungen" tabindex="-1">40.2.6. Besondere Perfekt-Bildungen <a class="header-anchor" href="#_40-2-6-besondere-perfekt-bildungen" aria-label="Permalink to &quot;40.2.6. Besondere Perfekt-Bildungen&quot;">​</a></h3><p>विद् 2P präsentisches Perfekt:</p><ul><li><p>1.sg.P वेद (= 3.sg.P)</p></li><li><p>1.pl.P विद्म</p></li></ul><p>अह् 1. Person nicht gebräuchlich!</p><p>भू 1P</p><ul><li><p>1.sg.P बभूव (= 3.sg.P)</p></li><li><p>1.pl.P बभुविम</p></li></ul><p>जि 1P</p><ul><li><p>1.sg.P जिगाय (= 3.sg.P) । जिगय</p></li><li><p>1.pl.P जिग्यिम (ji-gi + i + ma !)</p></li></ul><h2 id="_40-3-bildung-der-verbformen-der-ersten-person-des-periphrastischen-perfekt-अनुप्रयोगलिट्" tabindex="-1">40.3. Bildung der Verbformen der ersten Person des periphrastischen Perfekt (अनुप्रयोगलिट्) <a class="header-anchor" href="#_40-3-bildung-der-verbformen-der-ersten-person-des-periphrastischen-perfekt-अनुप्रयोगलिट्" aria-label="Permalink to &quot;40.3. Bildung der Verbformen der ersten Person des periphrastischen Perfekt (अनुप्रयोगलिट्)&quot;">​</a></h2><p>Das periphrastische Perfekt wird gebildet von:</p><ul><li>abgeleiteten Verbalstämme (Kausativ, Desiderativ, Frequentativ, Denominativa), insbesondere Kausativ</li><li>Wurzeln, die mit langem Vokal (außer ā) beginnen</li><li>Wurzeln: Vokal (außer a-)-Konsonant-Konsonant</li><li>einigen anderen</li><li>bei einigen Wurzeln können beide Perfekte optionell gebildet werden: uṣ &quot;brennen&quot;, vid &quot;wissen&quot;, jāgṛ &quot;wachen&quot;, daridrā &quot;arm sein&quot;</li><li>bei folgende Wurzeln  können beide Perfekte optionell gebildet werden und auch das periphrastische Perfekt ist redupliziert, und zwar mit der Reduplikationssilbe des Präsensstamms: <ul><li>bhī &quot;sich fürchten&quot;</li><li>bhṛ &quot;tragen&quot;</li><li>hu &quot;opfern&quot;</li><li>hrī &quot;sich schämen&quot;</li></ul></li></ul><p>ईक्ष् 1Ā</p><ul><li><p>1.sg.Ā ईक्षां चक्रे । ईक्षामास । ईक्षां बभूव</p></li><li><p>1.pl.Ā ईक्षां चकृमहे । ईक्षामासिम । ईक्षां बभूविम</p></li></ul><p>बन्ध् Kausativum P: बन्धयति</p><ul><li><p>1.sg.P बन्धयां चकर । बन्धयां चकार (= 3.sg.P) । बन्धयामास (= 3.sg.P) । बन्धयां बभूव (= 3.sg.P)</p></li><li><p>1.pl.P बन्धयां चकृम । बन्धयामासिम । बन्धयां बभूविम</p></li></ul><h2 id="_40-4-syntaktisches-zur-ersten-person-तृतीयः" tabindex="-1">40.4. Syntaktisches zur ersten Person (तृतीयः) <a class="header-anchor" href="#_40-4-syntaktisches-zur-ersten-person-तृतीयः" aria-label="Permalink to &quot;40.4. Syntaktisches zur ersten Person (तृतीयः)&quot;">​</a></h2><p>Da ein Verbum finitum (konjugiertes Verb) den Agens (कर्तृ) mit ausdrückt, braucht das &quot;ich&quot;, &quot;wir&quot; in nicht-passiven Verbalsätzen mit Verbum finitum nicht extra durch ein Personalpronomen ausgedrückt werden</p><h2 id="_40-5-personalpronomen-पुरुषार्थकसर्वनाम-der-1-person-singular-und-plural" tabindex="-1">40.5. Personalpronomen (पुरुषार्थकसर्वनाम) der 1. Person Singular und Plural <a class="header-anchor" href="#_40-5-personalpronomen-पुरुषार्थकसर्वनाम-der-1-person-singular-und-plural" aria-label="Permalink to &quot;40.5. Personalpronomen (पुरुषार्थकसर्वनाम) der 1. Person Singular und Plural&quot;">​</a></h2><p>Die Form des Personalpronomens (persönlichen Fürworts) ist für alle Geschlechter dieselbe.</p><p>|   | एकवचनम्<br> &quot;ich&quot; | बहुवचनम्<br> &quot;wir&quot; | | --- | --- | --- | | प्रथमा | अहम् | वयम् | | द्वितीया | माम्<br> मा | अस्मान्<br> नस् | | तृतीया | मया | अस्माभिस् | | चतुर्थी | मय्हम्<br> मे | अस्मभ्यम्<br> नस् | | पञ्चमी | मत् | अस्मत् | | षष्ठी | मम<br> मे | अस्माकम्<br> नस् | | सप्तमी | मयि | अस्मासु |</p><p>Die kürzeren Formen, die oben an zweiter Stelle stehen (मा, मे, नस्) dürfen nie am Anfang eines Satzes oder Verses gebraucht werden.</p><p>Vor den Partikeln च, वा, एव dürfen diese sog. enklitischen Formen ebenfalls nicht gebraucht werden:</p><p>nur: ... मां च ... &quot;und mich&quot;</p><p>Der Genetiv (षष्ठी) der Personalpronomina wird als besitzanzeigendes Fürwort verwendet:</p><p>मम । मे = &quot;mein&quot;</p><p>अस्माकम् । नस् = &quot;unser&quot;</p><p>Als Vorderglied von Komposita stehen für diese Pronomina die Stämme:</p><ul><li>sg. मद्</li><li>pl. अस्मद्</li></ul><p>z.B. मत्पुस्तकम् &quot;mein Buch&quot; ; अस्मद्पुस्तकानि &quot;unsere Bücher&quot;</p><h2 id="_40-6-wortliste" tabindex="-1">40.6. Wortliste <a class="header-anchor" href="#_40-6-wortliste" aria-label="Permalink to &quot;40.6. Wortliste&quot;">​</a></h2><p>पात्र n.: Ehrwürdiger, Meister, Würdiger</p><p>मेधा f.: Weisheit, Verstand, Gedanke</p><p>पुस्तक m.n.: Manuskript, Buch</p><p>कॢप् 1Ā कल्पते : in richtiger Ordnung sein, passen zu (Lok.) ; sich gestalten, sich bilden ; sich entschließen zu, sich bequemen zu (Dativ)</p><blockquote><p>Perf. II चकॢपे fakultativ अनिट्<br> Fut. कल्पिष्यते । कल्प्स्यते<br> Kaus. कल्पयति : in Ordnung bringen, schaffen, in der Phantasie bilden, sich einbilden<br> PPP कॢप्त<br> Inf. कल्पितुम् । कल्प्तुम्</p><p>davon:</p><p>कल्पना f.: Das Bilden in Gedanken, Annahme von etwas in der Wirklichkeit nicht Existierendem, Fiktion</p></blockquote><p>कॢप् + वि Kaus. विकल्पयति : (sich verschieden vorstellen =) in Frage stellen, bezweifeln</p><blockquote><p>davon:</p><p>विक्ल्प m.: Alternative, Zweifel</p></blockquote><p>तुद् 6U तुदति : schlagen</p><blockquote><p>Perf. II तुतोद, तुतुदुर्<br> Fut. तोत्स्यति<br> Pass. तुद्यते<br> Kaus. तोदयति<br> PPP तुन्न (tud + na)<br> Inf. तोत्तुम्</p></blockquote><p>तॄ 1P तरति :  hinübergehen, überschreiten, sich retten vor jemandem (Akk. = jemanden überschreiten)</p><blockquote><p>Perf. IIIb ततार, ततरुर् । तेरुर्<br> Fut. तरिष्यति । तरीष्यति<br> Pass. तीर्यते<br> Kaus. तारयति<br> PPP तीर्ण<br> Inf. तरितुम् । तरीतुम्</p><p>davon:</p><p>तीर्थ n.: Furt, heiliger Badeplatz, Pilgerort</p></blockquote><p><img src="'+a+'" alt=""><br> Abb.: हरिद्वारे तीर्थम्<br> [Bildquelle: mckaysavage. -- <a href="http://www.flickr.com/photos/mckaysavage/2085710183/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/mckaysavage/2085710183/</a>. -- Zugriff am 2009-01-02. -- <a href="http://creativecommons.org/licenses/by/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons lizenz (Namensnennung)]</p><blockquote><p>तीर्थङ्कर m. (aus: तीर्थम्+ कृ): Furtmacher (über das Leid hinweg) = die 24 Lehrer der Jaina</p></blockquote><p><img src="'+s+'" alt=""><br> Abb.: तीर्थङ्करः<br> [Bildquelle: wallyg. -- <a href="http://www.flickr.com/photos/wallyg/1657905479/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/wallyg/1657905479/</a>. -- Zugriff am 2009-01-02. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>अव Präverb.: herab, hinab, weg, ab-</p><p>तॄ + अव 1P अवतरति : herabsteigen</p><blockquote><p>davon:</p><p>अवतार m.: (Herabsteiger, Herabstieg) Inkarnation eines Gottes, bes. Viṣṇus 10 Inkarnationen (s. Basham, Wonder S. 304 - 309)</p></blockquote><p><img src="'+o+'" alt=""><br> Abb.: विष्णोर्दशावताराः<br> Im Uhrzeigersinn: मत्स्य, कुर्म, वाराह, वामन, कृष्ण, कल्कि, बुद्ध, प्रशुराम, राम, नरसिंह, in der Mitte: कृष्ण[Bildquelle: Wikipedia. Public domain]</p><p>स्वप् 2P स्वपिति,  स्वपन्ति : schlafen, sich schlafen legen</p><blockquote><p>Impf. अस्वपीत् । अस्वपत्<br> Perf. सुष्वाप, सुषुपुर्<br> Fut. स्वप्स्यति<br> Pass. सुप्यते (aus *svp-ya-te)<br> Kaus. स्वापयति<br> PPP सुप्त<br> Inf. स्वप्तुम्</p><p>davon:</p><p>स्वप्न m.: Schlaf, Traum</p><p>सुप्ति f. (aus *svp-ti): Schlaf, bes. Tiefschlaf</p></blockquote><p><img src="'+p+'" alt=""><br> Abb.: स्वपन्ति<br> Indische Flughunde (<em>Pteropus giganteus</em>), Ahmedabad = અમદાવાદ<br> [Bildquelle: Umang Dutt. -- <a href="http://www.flickr.com/photos/snapflickr/2456084948/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/snapflickr/2456084948/</a>. -- Zugriff am 2009-01-02. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><h2 id="_40-7-ubung" tabindex="-1">40.7. Übung <a class="header-anchor" href="#_40-7-ubung" aria-label="Permalink to &quot;40.7. Übung&quot;">​</a></h2><p>A) Übersetzen sie die सुभाषितानि am Beginn der Lektion.</p><p>B) Verwandeln Sie folgende Verbalformen in die entsprechenden Perfektformen. Bei mehreren Möglichkeiten, geben Sie bitte alle Möglichkeiten an.</p><p>(Zeichenerklärung: अ = अनिट्, इ = fakultativ अनिट्)</p><ol><li>अश्नीमः</li><li>स्मः</li><li>स्रक्ष्यामि</li><li>स्तुमहे अ</li><li>वर्धामहे</li><li>आवर्ते</li><li>सेक्ष्यामि</li><li>अलुभ्याम</li><li>रुन्धे</li><li>रोदिमि</li><li>अयुध्यामहि</li><li>युञ्ज्मः</li><li>अजानीम</li><li>ददामि</li><li>अबिभयम्</li><li>वच्मः</li><li>कामये</li><li>वसामः</li><li>अभवाम</li><li>अस्यामि</li><li>अबिभ्रि अ</li><li>कल्पामहे इ</li><li>त्यज्यामि</li><li>अतरम्</li><li>चिन्मः</li><li>पृच्छामः</li><li>अनश्याम इ</li><li>चरामः</li><li>अवदाम</li><li>शोचयामः</li><li>दध्महे</li><li>पिबामि</li><li>धरामः</li><li>म्रिये</li><li>दूषयामः</li><li>मन्ये</li><li>स्वपिमः</li><li>पामि</li><li>शृणुमः अ</li><li>अतुदम्</li><li>अमिमि</li><li>तिष्ठामि</li><li>अवहाम</li><li>अकुर्महि अ</li><li>जहीमः</li><li>अस्पृशम्</li><li>नेष्यामः</li><li>तन्महे</li><li>अक्रीणि</li><li>पुने</li><li>भुञ्ज्मः</li><li>स्मरिष्यामः</li><li>अभजाम (geht nach Typ Vb)</li><li>जेष्यामः</li><li>आसे (periphrast.)</li><li>विन्दामः</li><li>धक्ष्यामः</li><li>शक्नुमह्</li><li>भिनद्मि</li><li>भोत्स्ये</li><li>लभे</li><li>नर्तिष्यामि</li><li>अगमयम्</li><li>द्विष्महे</li><li>चोरये</li><li>अजुहुम</li><li>अहनम्</li><li>पश्यामः</li><li>ईक्षे</li></ol><h2 id="_40-8-wiederholungsubung-zur-formenlehre" tabindex="-1">40.8. Wiederholungsübung zur Formenlehre <a class="header-anchor" href="#_40-8-wiederholungsubung-zur-formenlehre" aria-label="Permalink to &quot;40.8. Wiederholungsübung zur Formenlehre&quot;">​</a></h2><ol><li>ददे</li><li>ददते</li><li>पापे</li><li>आसे</li><li>एते</li><li>इते</li><li>इतः</li><li>यतः</li><li>यते</li><li>ईयते</li><li>यत्</li><li>यदा</li><li>अस्तुवि</li><li>अस्तुवति</li><li>अस्तवीत्</li><li>ब्रह्मिणः</li><li>ब्रह्मणः</li><li>ब्राह्मणः</li><li>लभे</li><li>लाभे</li><li>लेभे</li><li>लोभे</li><li>काश्चन</li><li>तन्त्रे</li><li>तत्र</li><li>मनौ</li><li>मेने</li><li>सत्स्यामि</li><li>वेत्स्यामः</li><li>कच्चित्</li><li>तत्त्यागः</li><li>तत्याज</li><li>विद्ये</li><li>विद्याम्</li><li>एनेन</li><li>ऐक्षे</li><li>आह</li><li>आहन्</li></ol>',146)])])}const P=i(u,[["render",h]]);export{g as __pageData,P as default};
